+/// Generate a conformance test for a single extension.
+macro_rules! conformance_test {
+    ($name:ident, $ext_id:literal) => {
+        #[test]
+        fn $name() {
+            run_conformance_test($ext_id);
+        }
+    };
+    ($name:ident, $ext_id:literal, ignore) => {
+        #[test]
+        #[ignore]
+        fn $name() {
+            run_conformance_test($ext_id);
+        }
+    };
+}
